{"version":3,"sources":["pages/action/execute.uvue","App.uvue"],"sourcesContent":["<template>\r\n  <view class=\"page\">\r\n    <view class=\"bg-glow glow-purple\"></view>\r\n    <view class=\"bg-glow glow-blue\"></view>\r\n    <view class=\"bg-glow glow-pink\"></view>\r\n    <view class=\"sky-star star-a\"></view>\r\n    <view class=\"sky-star star-b\"></view>\r\n    <view class=\"sky-star star-c\"></view>\r\n    <view class=\"sky-star star-d\"></view>\r\n    <view class=\"sky-star star-e\"></view>\r\n    <view class=\"sky-star star-f\"></view>\r\n    <view class=\"sky-star star-g\"></view>\r\n    <view class=\"sky-star star-h\"></view>\r\n    <view class=\"sky-star star-i\"></view>\r\n    <view class=\"sky-star star-j\"></view>\r\n    <view class=\"sky-star star-k\"></view>\r\n    <view class=\"sky-star star-l\"></view>\r\n    <view class=\"back-button\" @tap=\"goBack\">\r\n      <text class=\"back-icon\">‹</text>\r\n    </view>\r\n    <view class=\"action-container\">\r\n      <text class=\"ritual-label\">{{ ritualLabel }}</text>\r\n      <text class=\"action-title\">{{ actionName }}</text>\r\n      <text class=\"action-subtitle\">{{ executeIntro }}</text>\r\n\r\n      <view class=\"lottie-stage\" :class=\"lottiePlaying ? 'lottie-stage-playing' : 'lottie-stage-paused'\">\r\n        <view class=\"lottie-glow\">\r\n          <view class=\"lottie-orbit\"></view>\r\n          <view class=\"icon-display\">\r\n            <text class=\"action-icon\">{{ iconEmoji }}</text>\r\n          </view>\r\n        </view>\r\n        <text class=\"lottie-placeholder\">{{ lottieStateText }}</text>\r\n        <view class=\"lottie-controls\">\r\n          <view class=\"lottie-chip\" @tap=\"toggleLottiePlaying\">\r\n            <text class=\"lottie-chip-text\">{{ lottiePlaying ? '暂停' : '播放' }}</text>\r\n          </view>\r\n          <view class=\"lottie-chip\" :class=\"lottieLoop ? 'lottie-chip-active' : ''\" @tap=\"toggleLottieLoop\">\r\n            <text class=\"lottie-chip-text\" :class=\"lottieLoop ? 'lottie-chip-text-active' : ''\">{{ lottieLoop ? '循环中' : '循环' }}</text>\r\n          </view>\r\n        </view>\r\n      </view>\r\n\r\n      <text v-if=\"!showCountdown\" class=\"tts-text\">{{ actionTtsText }}</text>\r\n      <text v-if=\"showCountdown\" class=\"tts-text execute-guide\">{{ executeGuide }}</text>\r\n\r\n      <view v-if=\"showCountdown\">\r\n        <CountdownBar :total=\"actionDuration\" :remaining=\"remainingMs\" />\r\n      </view>\r\n\r\n      <view v-if=\"showButtons\" class=\"button-group\">\r\n        <button class=\"action-btn action-primary\" @tap=\"handleAgree\">好啊</button>\r\n        <button class=\"action-btn action-secondary\" @tap=\"handleSelfReported\">我做过了</button>\r\n        <button class=\"action-btn action-ghost\" @tap=\"handleBusy\">现在忙，晚点提醒我</button>\r\n      </view>\r\n\r\n      <view v-if=\"showSkip\" class=\"button-group\">\r\n        <button class=\"action-btn action-ghost\" @tap=\"handleSkipDuringExec\">跳过这次</button>\r\n      </view>\r\n    </view>\r\n\r\n    <EncourageToast :visible=\"showEncourage\" :text=\"encourageText\" />\r\n\r\n    <FeedbackDialog :visible=\"showFeedback\" @confirm=\"onFeedbackConfirm\" @cancel=\"onFeedbackCancel\" />\r\n\r\n  </view>\r\n</template>\r\n\r\n<script setup lang=\"uts\">\r\nimport CountdownBar from '../../components/CountdownBar.uvue'\r\nimport EncourageToast from '../../components/EncourageToast.uvue'\r\nimport FeedbackDialog from '../../components/FeedbackDialog.uvue'\r\nimport { MicroAction } from '../../models/MicroAction'\r\nimport { getActionById } from '../../constants/Actions'\r\nimport { getRandomEncourage } from '../../constants/EncourageTexts'\r\nimport { insertManualActionLog } from '../../database/ActionLogDao'\r\nimport { onCompleted, onConsecutiveSkip } from '../../services/RuleEngine'\r\nimport { takeActionId } from '../../utils/NavigationHelper'\r\nimport { shortVibrate } from '../../utils/VibrateUtils'\r\nimport { getExecuteGuide, getExecuteIntro } from '../../constants/MicroPlanetCopy'\r\n\r\nconst actionId = ref<string>('')\r\nconst action = ref<MicroAction | null>(null)\r\nconst isExecuting = ref<boolean>(false)\r\nconst isCompleted = ref<boolean>(false)\r\nconst showEncourage = ref<boolean>(false)\r\nconst encourageText = ref<string>('')\r\nconst showFeedback = ref<boolean>(false)\r\nconst remainingMs = ref<number>(0)\r\nconst lottiePlaying = ref<boolean>(true)\r\nconst lottieLoop = ref<boolean>(true)\r\nlet countdownTimerId: number | null = null\r\n\r\nconst showButtons = computed<boolean>((): boolean => {\r\n  const a = action.value\r\n  const exec = isExecuting.value\r\n  const done = isCompleted.value\r\n  return a != null && exec === false && done === false\r\n})\r\n\r\nconst showCountdown = computed<boolean>((): boolean => {\r\n  return isExecuting.value === true\r\n})\r\n\r\nconst showSkip = computed<boolean>((): boolean => {\r\n  const exec = isExecuting.value\r\n  const done = isCompleted.value\r\n  return exec === true && done === false\r\n})\r\n\r\nconst actionName = computed<string>((): string => {\r\n  const a = action.value\r\n  return a != null ? a.name : '未找到动作'\r\n})\r\n\r\nconst actionTtsText = computed<string>((): string => {\r\n  const a = action.value\r\n  return a != null ? a.ttsText : ''\r\n})\r\n\r\nconst actionDuration = computed<number>((): number => {\r\n  const a = action.value\r\n  return a != null ? a.defaultDurationMs : 0\r\n})\r\n\r\nconst iconEmoji = computed<string>((): string => {\r\n  const a = action.value\r\n  if (a == null) return '?'\r\n  const id = a.id\r\n  if (id === 'eye_blink') return '👁'\r\n  if (id === 'eye_rotate') return '👀'\r\n  if (id === 'neck_rotate') return '🔄'\r\n  if (id === 'shoulder_roll') return '💪'\r\n  if (id === 'neck_stretch') return '🧘'\r\n  if (id === 'core_tighten') return '🔥'\r\n  if (id === 'heel_raise') return '🦶'\r\n  if (id === 'deep_breath') return '🌬'\r\n  if (id === 'far_gaze') return '🏔'\r\n  return '?'\r\n})\r\n\r\nconst executeIntro = computed<string>((): string => getExecuteIntro(actionId.value))\r\nconst executeGuide = computed<string>((): string => getExecuteGuide(actionId.value))\r\nconst ritualLabel = computed<string>((): string => isExecuting.value ? '正在点亮小星球' : '10 秒健康仪式')\r\nfunction getActionCueText(id: string): string {\r\n  if (id === 'eye_blink') return '轻闭双眼 2 秒后睁开，重复眨眼，让眼表重新湿润'\r\n  if (id === 'eye_rotate') return '眼球缓慢画圈，顺时针一圈后再逆时针一圈'\r\n  if (id === 'neck_rotate') return '肩膀放松，头部慢慢转向一侧，停 3 秒后回正'\r\n  if (id === 'shoulder_roll') return '双肩向上提起，再向后画圈放下，保持动作缓慢'\r\n  if (id === 'neck_stretch') return '坐直身体，轻轻侧屈头颈，感受肩颈外侧被拉长'\r\n  if (id === 'core_tighten') return '收紧腹部和骨盆底，保持自然呼吸，不要憋气'\r\n  if (id === 'heel_raise') return '双脚踩稳，缓慢踮起脚跟，再控制速度落回地面'\r\n  if (id === 'deep_breath') return '鼻吸 4 秒让腹部鼓起，口呼 6 秒把气息慢慢送出'\r\n  if (id === 'far_gaze') return '看向 6 米外的固定目标，放松眉心和眼周肌肉'\r\n  return '跟随节奏完成这个微动作，保持放松、缓慢和可控'\r\n}\r\nconst lottieStateText = computed<string>((): string => lottiePlaying.value ? getActionCueText(actionId.value) : '动作已暂停，准备好后继续跟着节奏完成')\r\n\r\n/* ---------- leaf functions (no deps) ---------- */\r\n\r\nfunction toggleLottiePlaying(): void {\r\n  lottiePlaying.value = !lottiePlaying.value\r\n}\r\n\r\nfunction toggleLottieLoop(): void {\r\n  lottieLoop.value = !lottieLoop.value\r\n}\r\n\r\nfunction goBack(): void {\r\n  uni.navigateBack({})\r\n}\r\n\r\nfunction getActionIdFromOption(source: any): string {\r\n  if (source == null) return ''\r\n  try {\r\n    const obj = source as UTSJSONObject\r\n    if (obj == null) return ''\r\n    const raw = obj['actionId']\r\n    if (raw == null) return ''\r\n    const str = raw as string\r\n    return str\r\n  } catch (_) {\r\n    return ''\r\n  }\r\n}\r\n\r\nfunction clearCountdown(): void {\r\n  const tid = countdownTimerId\r\n  if (tid != null) {\r\n    clearInterval(tid)\r\n    countdownTimerId = null\r\n  }\r\n}\r\n\r\nfunction emitLlmActionCompleted(a: MicroAction, durationMs: number, result: string): void {\r\n  try {\r\n    uni.$emit('llmActionCompleted', {\r\n      actionId: a.id,\r\n      actionName: a.name,\r\n      actionCategory: a.category,\r\n      durationMs: durationMs,\r\n      result: result\r\n    })\r\n  } catch (e) {\r\n    console.warn('[execute] emitLlmActionCompleted 失败: ' + JSON.stringify(e))\r\n  }\r\n}\r\n\r\nfunction recordAction(result: string, skipReason: string = ''): void {\r\n  console.log('[execute] recordAction enter, result=' + result)\r\n  const a = action.value\r\n  if (a == null) {\r\n    console.log('[execute] recordAction SKIP: action.value is null')\r\n    return\r\n  }\r\n  const nowMs = Date.now()\r\n  const dur = result === 'completed' ? a.defaultDurationMs : Math.floor(a.defaultDurationMs - remainingMs.value)\r\n  const insertId = insertManualActionLog(\r\n    a.id,\r\n    a.category,\r\n    result,\r\n    skipReason.length > 0 ? skipReason : null,\r\n    dur,\r\n    a.defaultDurationMs,\r\n    nowMs - 30000,\r\n    nowMs,\r\n    Math.floor(nowMs / 1000)\r\n  )\r\n  console.log('[execute] insertActionLog 返回 id=' + insertId)\r\n  emitLlmActionCompleted(a, dur, result)\r\n}\r\n\r\n/* ---------- mid-layer functions ---------- */\r\n\r\nfunction showEncourageNow(): void {\r\n  const a = action.value\r\n  const cat = a != null ? a.category : ''\r\n  encourageText.value = getRandomEncourage(cat)\r\n  showEncourage.value = true\r\n  isCompleted.value = true\r\n  setTimeout((): void => {\r\n    showEncourage.value = false\r\n    uni.navigateBack({})\r\n  }, 1500)\r\n}\r\n\r\nfunction startCountdown(): void {\r\n  const interval = 100\r\n  console.log('[execute] startCountdown total=' + remainingMs.value + 'ms')\r\n  countdownTimerId = setInterval((): void => {\r\n    remainingMs.value -= interval\r\n    if (remainingMs.value <= 0) {\r\n      remainingMs.value = 0\r\n      clearCountdown()\r\n      recordAction('completed')\r\n      const a = action.value\r\n      onCompleted(a != null ? a.category : '')\r\n      showEncourageNow()\r\n    }\r\n  }, interval)\r\n}\r\n\r\nfunction handleAgree(): void {\r\n  console.log('[execute] handleAgree')\r\n  const a = action.value\r\n  if (a == null) {\r\n    uni.showToast({ title: '未找到动作', icon: 'none' })\r\n    return\r\n  }\r\n  isExecuting.value = true\r\n  remainingMs.value = a.defaultDurationMs\r\n  console.log('[execute] countdown start, ms=' + a.defaultDurationMs)\r\n  startCountdown()\r\n  shortVibrate(1)\r\n}\r\n\r\nfunction handleSelfReported(): void {\r\n  recordAction('self_reported')\r\n  showEncourageNow()\r\n}\r\n\r\nfunction handleBusy(): void {\r\n  recordAction('skipped', 'busy')\r\n  setTimeout((): void => { uni.navigateBack({}) }, 300)\r\n}\r\n\r\nfunction handleSkipDuringExec(): void {\r\n  clearCountdown()\r\n  showFeedback.value = true\r\n}\r\n\r\nfunction onFeedbackConfirm(reason: string): void {\r\n  showFeedback.value = false\r\n  recordAction('skipped', reason)\r\n  const a = action.value\r\n  onConsecutiveSkip(a != null ? a.category : '')\r\n  showEncourageNow()\r\n}\r\n\r\nfunction onFeedbackCancel(): void {\r\n  showFeedback.value = false\r\n  isExecuting.value = false\r\n  uni.navigateBack({})\r\n}\r\n\r\n/* ---------- lifecycle hooks (must be LAST) ---------- */\r\n\r\nonLoad((option) => {\r\n  console.log('[execute] onLoad begin')\r\n  let aid = takeActionId()\r\n  console.log('[execute] from helper aid=' + aid)\r\n  if (aid.length < 1) {\r\n    aid = getActionIdFromOption(option)\r\n    console.log('[execute] from option aid=' + aid)\r\n  }\r\n  actionId.value = aid\r\n  if (aid.length > 0) {\r\n    const found = getActionById(aid)\r\n    action.value = found\r\n    console.log('[execute] found action=' + (found != null ? found.name : 'null'))\r\n  } else {\r\n    console.log('[execute] no actionId')\r\n  }\r\n})\r\n\r\nonUnload((): void => {\r\n  clearCountdown()\r\n})\r\n</script>\r\n\r\n<style scoped>\r\n.page {\r\n  flex: 1;\r\n  background-color: #F5F6FA;\r\n  justify-content: center;\r\n  align-items: center;\r\n}\r\n.action-container {\r\n  width: 85%;\r\n  background-color: #FFFFFF;\r\n  border-radius: 16px;\r\n  padding: 24px;\r\n  flex-direction: column;\r\n  align-items: center;\r\n}\r\n.action-title {\r\n  font-size: 22px;\r\n  font-weight: bold;\r\n  color: #2C3E50;\r\n  margin-bottom: 16px;\r\n}\r\n.icon-display {\r\n  width: 100px;\r\n  height: 100px;\r\n  justify-content: center;\r\n  align-items: center;\r\n  background-color: #F0F3F4;\r\n  border-radius: 50px;\r\n  margin-bottom: 16px;\r\n}\r\n.action-icon {\r\n  font-size: 48px;\r\n}\r\n.tts-text {\r\n  font-size: 15px;\r\n  color: #7F8C8D;\r\n  text-align: center;\r\n  margin-bottom: 20px;\r\n  padding: 0 16px;\r\n}\r\n.button-group {\r\n  width: 100%;\r\n  flex-direction: column;\r\n  margin-top: 16px;\r\n}\r\n.action-btn {\r\n  width: 100%;\r\n  padding: 14px;\r\n  border-radius: 10px;\r\n  font-size: 16px;\r\n  text-align: center;\r\n  margin-bottom: 8px;\r\n  border-width: 0;\r\n}\r\n.action-primary {\r\n  background-color: #DBC8ED;\r\n  color: #161A33;\r\n  font-weight: bold;\r\n}\r\n.action-secondary {\r\n  background-color: rgba(219, 200, 237, 0.16);\r\n  color: rgba(255, 255, 255, 0.72);\r\n}\r\n.action-ghost {\r\n  background-color: rgba(255, 255, 255, 0.08);\r\n  color: rgba(255, 255, 255, 0.72);\r\n}\r\n.dialog-overlay {\r\n  position: fixed;\r\n  top: 0;\r\n  left: 0;\r\n  right: 0;\r\n  bottom: 0;\r\n  justify-content: center;\r\n  align-items: center;\r\n  background-color: rgba(0, 0, 0, 0.4);\r\n  z-index: 999;\r\n}\r\n.dialog-content {\r\n  width: 280px;\r\n  background-color: #FFFFFF;\r\n  border-radius: 14px;\r\n  padding: 20px;\r\n  flex-direction: column;\r\n}\r\n.dialog-title {\r\n  font-size: 17px;\r\n  font-weight: bold;\r\n  color: #2C3E50;\r\n  text-align: center;\r\n  margin-bottom: 12px;\r\n}\r\n.dialog-body-text {\r\n  font-size: 14px;\r\n  color: #34495E;\r\n  line-height: 20px;\r\n  text-align: center;\r\n  margin-bottom: 16px;\r\n}\r\n.dialog-actions {\r\n  flex-direction: row;\r\n  justify-content: space-between;\r\n}\r\n.cancel-btn {\r\n  flex: 1;\r\n  margin-right: 8px;\r\n  padding: 10px;\r\n  border-radius: 8px;\r\n  background-color: #ECF0F1;\r\n  color: #7F8C8D;\r\n  font-size: 14px;\r\n  text-align: center;\r\n  border-width: 0;\r\n}\r\n.confirm-btn {\r\n  flex: 1;\r\n  margin-left: 8px;\r\n  padding: 10px;\r\n  border-radius: 8px;\r\n  background-color: #DBC8ED;\r\n  color: #161A33;\r\n  font-size: 14px;\r\n  text-align: center;\r\n  border-width: 0;\r\n}\r\n\r\n.page {\r\n  background-color: #F4F8FB;\r\n  justify-content: flex-start;\r\n  align-items: center;\r\n  padding-top: 24px;\r\n}\r\n.action-container {\r\n  width: 88%;\r\n  background-color: #FFFFFF;\r\n  border-radius: 28px;\r\n  padding: 26px 22px 22px 22px;\r\n  box-shadow: 0 14px 36px rgba(88, 122, 139, 0.12);\r\n}\r\n.ritual-label {\r\n  font-size: 12px;\r\n  color: #8E7DD6;\r\n  font-weight: bold;\r\n  margin-bottom: 8px;\r\n}\r\n.action-title {\r\n  font-size: 25px;\r\n  color: #243642;\r\n  margin-bottom: 8px;\r\n}\r\n.action-subtitle {\r\n  font-size: 14px;\r\n  color: #6F8490;\r\n  text-align: center;\r\n  line-height: 20px;\r\n  margin-bottom: 18px;\r\n  padding: 0 10px;\r\n}\r\n.icon-display {\r\n  width: 128px;\r\n  height: 128px;\r\n  border-radius: 64px;\r\n  background-color: #EAF8F1;\r\n  box-shadow: 0 12px 26px rgba(138, 217, 182, 0.24);\r\n  margin-bottom: 18px;\r\n}\r\n.action-icon {\r\n  font-size: 56px;\r\n}\r\n.tts-text {\r\n  font-size: 14px;\r\n  color: #6F8490;\r\n  line-height: 21px;\r\n  margin-bottom: 18px;\r\n  padding: 0 10px;\r\n}\r\n.execute-guide {\r\n  color: #4E6370;\r\n}\r\n.button-group {\r\n  margin-top: 14px;\r\n}\r\n.action-btn {\r\n  border-radius: 18px;\r\n  margin-bottom: 10px;\r\n  border-width: 0;\r\n  font-size: 15px;\r\n}\r\n.primary {\r\n  background-color: #8C6FFF;\r\n  color: #FFFFFF;\r\n  font-weight: bold;\r\n}\r\n.secondary {\r\n  background-color: #F1F8F5;\r\n  color: #4A9B7B;\r\n}\r\n.ghost {\r\n  background-color: #F4F8FB;\r\n  color: #6F8490;\r\n}\r\n.dialog-content {\r\n  border-radius: 24px;\r\n  box-shadow: 0 14px 36px rgba(88, 122, 139, 0.18);\r\n}\r\n.dialog-title {\r\n  color: #243642;\r\n}\r\n.dialog-body-text {\r\n  color: #6F8490;\r\n}\r\n.cancel-btn {\r\n  border-radius: 14px;\r\n  background-color: #F1F6F7;\r\n  color: #6F8490;\r\n}\r\n.confirm-btn {\r\n  border-radius: 14px;\r\n  background-color: #8C6FFF;\r\n}\r\n\r\n.page {\r\n  background-color: #F6F2FF;\r\n  background-image: linear-gradient(180deg, #EFE8FF 0%, #F4FAFF 100%);\r\n}\r\n.action-container {\r\n  background-color: rgba(255, 255, 255, 0.9);\r\n  border-width: 1px;\r\n  border-color: rgba(255, 255, 255, 0.78);\r\n  border-style: solid;\r\n  box-shadow: 0 20px 46px rgba(96, 84, 172, 0.22);\r\n}\r\n.ritual-label {\r\n  color: #8C6FFF;\r\n}\r\n.action-title {\r\n  color: #25223D;\r\n  font-size: 28px;\r\n}\r\n.action-subtitle {\r\n  color: #706A97;\r\n}\r\n.lottie-stage {\r\n  width: 100%;\r\n  min-height: 196px;\r\n  border-radius: 30px;\r\n  background-color: #F1EEFF;\r\n  background-image: linear-gradient(135deg, #F5EDFF 0%, #EAF5FF 100%);\r\n  align-items: center;\r\n  justify-content: center;\r\n  padding: 18px 14px;\r\n  margin-bottom: 18px;\r\n  border-width: 1px;\r\n  border-color: rgba(255, 255, 255, 0.75);\r\n  border-style: solid;\r\n}\r\n.lottie-stage-playing {\r\n  box-shadow: 0 16px 34px rgba(110, 90, 232, 0.2);\r\n}\r\n.lottie-stage-paused {\r\n  opacity: 0.86;\r\n}\r\n.lottie-glow {\r\n  width: 128px;\r\n  height: 128px;\r\n  border-radius: 64px;\r\n  align-items: center;\r\n  justify-content: center;\r\n  background-color: rgba(201, 182, 255, 0.34);\r\n  margin-bottom: 10px;\r\n}\r\n.lottie-orbit {\r\n  position: absolute;\r\n  width: 122px;\r\n  height: 48px;\r\n  border-radius: 61px;\r\n  border-width: 2px;\r\n  border-color: rgba(110, 90, 232, 0.42);\r\n  border-style: solid;\r\n}\r\n.icon-display {\r\n  width: 90px;\r\n  height: 90px;\r\n  border-radius: 45px;\r\n  background-color: #BFD5FF;\r\n  background-imag